import ReactDOM from "react-dom/client";
import "./index.css";
import App from "./App";
import cors from "cors";

application.use(cors)

// React 18 way of rendering
const root = ReactDOM.createRoot(document.getElementById("root"));
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);
